// ─── UTILITY FUNCTIONS ───────────────────────────────────────────────────────

function stripAccents(str) {
  return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function normaliseInput(str) {
  return stripAccents(str.trim().toUpperCase()).replace(/[-\s.]/g, '');
}

// Pre-bucket the players array
function buildBuckets() {
  const buckets = { 4: [], 5: [], 6: [], '7plus': [] };
  PLAYERS.forEach(p => {
    const len = p.surname.length;
    if (len === 4) buckets[4].push(p);
    else if (len === 5) buckets[5].push(p);
    else if (len === 6) buckets[6].push(p);
    else if (len >= 7) buckets['7plus'].push(p);
  });
  return buckets;
}

const BUCKETS = buildBuckets();

// Deterministic daily pick — same player for all users on the same day, different per mode
function getDailyPlayer(bucket, dateStr) {
  const players = BUCKETS[bucket];
  if (!players || players.length === 0) return null;
  let hash = 0;
  for (let i = 0; i < dateStr.length; i++) {
    hash = ((hash << 5) - hash) + dateStr.charCodeAt(i);
    hash |= 0;
  }
  const bucketSeed = String(bucket).split('').reduce((a, c) => a + c.charCodeAt(0), 0);
  const idx = Math.abs(hash + bucketSeed) % players.length;
  return players[idx];
}

function getTodayStr() {
  return new Date().toISOString().slice(0, 10);
}

function evaluateGuess(guess, target) {
  const result = Array(target.length).fill('absent');
  const targetArr = target.split('');
  const guessArr = guess.split('');
  const targetUsed = Array(target.length).fill(false);
  const guessUsed = Array(guess.length).fill(false);

  for (let i = 0; i < target.length; i++) {
    if (guessArr[i] === targetArr[i]) {
      result[i] = 'correct';
      targetUsed[i] = true;
      guessUsed[i] = true;
    }
  }
  for (let i = 0; i < guess.length; i++) {
    if (guessUsed[i]) continue;
    for (let j = 0; j < target.length; j++) {
      if (targetUsed[j]) continue;
      if (guessArr[i] === targetArr[j]) {
        result[i] = 'present';
        targetUsed[j] = true;
        guessUsed[i] = true;
        break;
      }
    }
  }
  return result;
}

// ─── COMPONENTS ─────────────────────────────────────────────────────────────

const BUCKET_LABELS = {
  4: '4 Letters',
  5: '5 Letters',
  6: '6 Letters',
  '7plus': '7+ Letters',
};

const TILE_COLORS = {
  correct: '#3d8a3e',
  present: '#b5943a',
  absent:  '#3a3a3c',
};

const TILE_BORDERS = {
  correct: '#3d8a3e',
  present: '#b5943a',
  absent:  '#3a3a3c',
  empty:   '#3a3a3c',
  tbd:     '#999',
};

function Tile({ letter, state, revealed, size = 52 }) {
  const isRevealed = revealed && state && state !== 'empty' && state !== 'tbd';
  const bg     = isRevealed ? TILE_COLORS[state] : 'transparent';
  const border = isRevealed ? TILE_BORDERS[state] : state === 'tbd' ? TILE_BORDERS.tbd : TILE_BORDERS.empty;
  const fontSize = size >= 50 ? 20 : size >= 40 ? 17 : size >= 30 ? 14 : 11;

  return (
    <div style={{
      width: size, height: size,
      border: `2px solid ${border}`,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      fontSize, fontWeight: 700,
      fontFamily: "'Arial Black', Arial, sans-serif",
      color: '#fff',
      background: bg,
      transition: isRevealed ? 'background 0.3s ease, border-color 0.3s ease' : 'none',
      userSelect: 'none',
      textTransform: 'uppercase',
      flexShrink: 0,
    }}>
      {letter}
    </div>
  );
}

function GuessRow({ guess, evaluation, target, isActive, currentInput, revealed }) {
  const len = target.length;
  const tileSize = len <= 6 ? 52 : len <= 9 ? 42 : len <= 13 ? 34 : len <= 16 ? 27 : 22;
  const gap = len <= 9 ? 5 : len <= 13 ? 4 : 3;

  return (
    <div style={{ display: 'flex', gap, justifyContent: 'center' }}>
      {Array.from({ length: len }).map((_, i) => {
        let letter = '';
        let state = 'empty';
        if (guess) {
          letter = guess[i] || '';
          state = evaluation ? evaluation[i] : 'tbd';
        } else if (isActive) {
          letter = currentInput[i] || '';
          state = letter ? 'tbd' : 'empty';
        }
        return <Tile key={i} letter={letter} state={state} revealed={!!evaluation && revealed} size={tileSize} />;
      })}
    </div>
  );
}

function Keyboard({ onKey, usedLetters }) {
  const rows = [
    ['Q','W','E','R','T','Y','U','I','O','P'],
    ['A','S','D','F','G','H','J','K','L'],
    ['ENTER','Z','X','C','V','B','N','M','⌫'],
  ];

  const getKeyColor = (key) => {
    const s = usedLetters[key];
    if (s === 'correct') return '#3d8a3e';
    if (s === 'present') return '#b5943a';
    if (s === 'absent')  return '#3a3a3c';
    return '#818384';
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 6, alignItems: 'center', marginTop: 16 }}>
      {rows.map((row, ri) => (
        <div key={ri} style={{ display: 'flex', gap: 5 }}>
          {row.map(key => {
            const isWide = key === 'ENTER' || key === '⌫';
            return (
              <button key={key} onClick={() => onKey(key)} style={{
                width: isWide ? 58 : 36, height: 56,
                background: getKeyColor(key),
                border: 'none', borderRadius: 4,
                color: '#fff', fontSize: isWide ? 11 : 14, fontWeight: 700,
                fontFamily: 'Arial, sans-serif', cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                transition: 'background 0.2s', userSelect: 'none',
              }}>
                {key}
              </button>
            );
          })}
        </div>
      ))}
    </div>
  );
}

function PlayerCard({ player, won, guessCount }) {
  const posColors = {
    'Goalkeeper': '#e8a838',
    'Defender':   '#3a7bd5',
    'Full-back':  '#3a7bd5',
    'Half-back':  '#5a9a3e',
    'Midfielder': '#5a9a3e',
    'Forward':    '#c0392b',
  };
  const posColor = posColors[player.position] || '#666';
  const resultMsg = won
    ? (guessCount === 1 ? 'Incredible!' : guessCount <= 2 ? 'Outstanding!' : guessCount <= 4 ? 'Well done!' : 'So close!')
    : 'Unlucky';

  return (
    <div style={{
      background: '#1a1a1b', border: '1px solid #3a3a3c',
      borderRadius: 12, padding: '24px 28px',
      maxWidth: 380, margin: '0 auto',
      color: '#fff', fontFamily: 'Arial, sans-serif',
    }}>
      {/* Result banner */}
      <div style={{ textAlign: 'center', marginBottom: 20, paddingBottom: 16, borderBottom: '1px solid #3a3a3c' }}>
        <div style={{ fontSize: 28, marginBottom: 4 }}>{won ? '⚽' : '😔'}</div>
        <div style={{ fontSize: 18, fontWeight: 700, color: won ? '#3d8a3e' : '#c0392b' }}>{resultMsg}</div>
        {won && (
          <div style={{ fontSize: 13, color: '#aaa', marginTop: 4 }}>
            Guessed in {guessCount} {guessCount === 1 ? 'attempt' : 'attempts'}
          </div>
        )}
      </div>

      {/* Player name */}
      <div style={{ textAlign: 'center', marginBottom: 16 }}>
        <div style={{ fontSize: 24, fontWeight: 900, letterSpacing: 1 }}>{player.displayName}</div>
      </div>

      {/* Flag + nationality + position */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10, marginBottom: 18, flexWrap: 'wrap' }}>
        {player.flag && (
          <span style={{ fontSize: 22, lineHeight: 1 }}>{player.flag}</span>
        )}
        <span style={{ fontSize: 15, color: '#ccc' }}>{player.nationality}</span>
        <span style={{ fontSize: 13, color: '#444' }}>·</span>
        <span style={{
          fontSize: 13, fontWeight: 700, background: posColor,
          color: '#fff', padding: '2px 10px', borderRadius: 20,
        }}>
          {player.position}
        </span>
      </div>

      {/* Stats */}
      <div style={{
        display: 'grid', gridTemplateColumns: '1fr 1fr 1fr',
        gap: 10, background: '#111', borderRadius: 8, padding: '14px 10px',
      }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 22, fontWeight: 900, color: '#ef4444' }}>{player.totalApps}</div>
          <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>APPEARANCES</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 22, fontWeight: 900, color: '#ef4444' }}>{player.goals}</div>
          <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>GOALS</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: '#ef4444', marginTop: 4 }}>{player.years}</div>
          <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>YEARS</div>
        </div>
      </div>
    </div>
  );
}

// ─── MAIN GAME ───────────────────────────────────────────────────────────────

function WordleGame({ bucketKey, hintEnabled, onBack }) {
  // Lock the date and target at mount time — prevents midnight tick changing
  // the answer mid-game if a player starts just before midnight
  const [today]  = useState(() => getTodayStr());
  const [target] = useState(() => getDailyPlayer(bucketKey, today));
  const targetWord = target ? target.surname : '';
  const wordLen = targetWord.length;
  const MAX_GUESSES = 6;
  const HINT_AFTER  = 4;

  const [guesses,      setGuesses]      = useState([]);
  const [currentInput, setCurrentInput] = useState('');
  const [gameOver,     setGameOver]     = useState(false);
  const [won,          setWon]          = useState(false);
  const [showCard,     setShowCard]     = useState(false);
  const [revealedRows, setRevealedRows] = useState([]);
  const [shake,        setShake]        = useState(false);
  const [message,      setMessage]      = useState('');

  // Timer
  const [elapsed,     setElapsed]      = useState(0);
  const timerRef                       = useRef(null);
  const startTimeRef                   = useRef(Date.now());

  // Score submission
  const [nameInput,   setNameInput]    = useState('');
  const [submitted,   setSubmitted]    = useState(false);

  // Start timer on mount, stop on game over
  useEffect(() => {
    startTimeRef.current = Date.now();
    timerRef.current = setInterval(() => {
      setElapsed(Math.floor((Date.now() - startTimeRef.current) / 1000));
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, []);

  useEffect(() => {
    if (gameOver) clearInterval(timerRef.current);
  }, [gameOver]);

  async function handleSubmitWordleScore() {
    if (!nameInput.trim()) return;
    await saveWordleScore({
      name: nameInput.trim().slice(0, 20),
      guesses: guesses.length,
      timeTaken: elapsed,
      bucket: bucketKey,
      date: today,
    });
    setSubmitted(true);
  }

  // Build keyboard colours — priority: correct > present > absent, never downgrade
  const PRIORITY = { correct: 3, present: 2, absent: 1 };
  const usedLetters = {};
  guesses.forEach(({ word, eval: ev }) => {
    word.split('').forEach((ch, i) => {
      const next = ev[i];
      const cur  = usedLetters[ch];
      if (!cur || PRIORITY[next] > PRIORITY[cur]) {
        usedLetters[ch] = next;
      }
    });
  });

  const showMessage = (msg) => {
    setMessage(msg);
    setTimeout(() => setMessage(''), 1800);
  };

  const submitGuess = useCallback(() => {
    if (gameOver) return;
    const input = normaliseInput(currentInput);
    if (input.length !== wordLen) {
      showMessage(`Need ${wordLen} letters`);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      return;
    }
    const ev = evaluateGuess(input, targetWord);
    const newGuesses = [...guesses, { word: input, eval: ev }];
    setGuesses(newGuesses);
    setCurrentInput('');

    const rowIdx = newGuesses.length - 1;
    setTimeout(() => setRevealedRows(prev => [...prev, rowIdx]), 100);

    const isWin = input === targetWord;
    if (isWin || newGuesses.length >= MAX_GUESSES) {
      setGameOver(true);
      setWon(isWin);
      setTimeout(() => setShowCard(true), 1600);
    }
  }, [currentInput, guesses, gameOver, targetWord, wordLen]);

  const handleKey = useCallback((key) => {
    if (gameOver) return;
    if (key === 'ENTER') {
      submitGuess();
    } else if (key === '⌫' || key === 'Backspace') {
      setCurrentInput(prev => prev.slice(0, -1));
    } else if (/^[A-Za-z]$/.test(key) && currentInput.length < wordLen) {
      setCurrentInput(prev => prev + key.toUpperCase());
    }
  }, [currentInput, gameOver, wordLen, submitGuess]);

  useEffect(() => {
    const handler = (e) => {
      if (e.ctrlKey || e.metaKey || e.altKey) return;
      handleKey(e.key === 'Backspace' ? '⌫' : e.key.toUpperCase());
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [handleKey]);

  if (!target) return <div style={{ color: '#fff', padding: 40 }}>No player found.</div>;

  const showHint = hintEnabled && guesses.length >= HINT_AFTER && !won;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '100%' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', width: '100%', maxWidth: 520, marginBottom: 20, padding: '0 10px' }}>
        <button onClick={onBack} style={{ background: 'none', border: 'none', color: '#aaa', cursor: 'pointer', fontSize: 24, padding: '4px 8px', lineHeight: 1 }}>←</button>
        <div style={{ flex: 1, textAlign: 'center' }}>
          <div style={{ color: '#fff', fontWeight: 700, fontSize: 16, fontFamily: 'Arial, sans-serif' }}>{BUCKET_LABELS[bucketKey]}</div>
          <div style={{ color: '#555', fontSize: 12, fontFamily: 'Arial, sans-serif' }}>{today}</div>
        </div>
        <div style={{ width: 40 }} />
      </div>

      {/* Toast */}
      {message && (
        <div style={{
          position: 'fixed', top: 80, left: '50%', transform: 'translateX(-50%)',
          background: '#fff', color: '#000', padding: '10px 20px',
          borderRadius: 6, fontWeight: 700, fontSize: 14, zIndex: 100,
          fontFamily: 'Arial, sans-serif', boxShadow: '0 4px 12px rgba(0,0,0,0.4)',
          whiteSpace: 'nowrap',
        }}>
          {message}
        </div>
      )}

      {/* Hint banner — fixed position so it never shifts the grid */}
      {showHint && (
        <div style={{
          position: 'fixed', top: 70, left: '50%', transform: 'translateX(-50%)',
          background: '#2a2a2b', border: '1px solid #b5943a',
          borderRadius: 8, padding: '8px 20px',
          color: '#b5943a', fontSize: 14,
          fontFamily: 'Arial, sans-serif', fontWeight: 600,
          zIndex: 50, whiteSpace: 'nowrap',
          boxShadow: '0 4px 16px rgba(0,0,0,0.5)',
        }}>
          💡 First name: <span style={{ color: '#fff' }}>{target.firstname}</span>
        </div>
      )}

      {/* Grid */}
      <div style={{
        display: 'flex', flexDirection: 'column', gap: 5, marginBottom: 16,
        transform: shake ? 'translateX(-6px)' : 'none',
        transition: shake ? 'none' : 'transform 0.15s',
      }}>
        {Array.from({ length: MAX_GUESSES }).map((_, rowIdx) => {
          const guessData = guesses[rowIdx];
          const isActive  = rowIdx === guesses.length && !gameOver;
          return (
            <GuessRow
              key={rowIdx}
              guess={guessData?.word}
              evaluation={guessData?.eval}
              target={targetWord}
              isActive={isActive}
              currentInput={currentInput}
              revealed={revealedRows.includes(rowIdx)}
            />
          );
        })}
      </div>

      {/* Keyboard */}
      {!showCard && <Keyboard onKey={handleKey} usedLetters={usedLetters} />}

      {/* Player card */}
      {showCard && (
        <div style={{ marginTop: 20, width: '100%', maxWidth: 420, padding: '0 10px' }}>
          <PlayerCard player={target} won={won} guessCount={guesses.length} />

          {/* Timer result */}
          {won && (
            <div style={{
              textAlign: 'center', marginTop: 8, marginBottom: 4,
              fontSize: 13, color: '#aaa', fontFamily: 'Arial, sans-serif',
            }}>
              ⏱ Solved in {guesses.length} {guesses.length === 1 ? 'guess' : 'guesses'} · {Math.floor(elapsed / 60)}:{String(elapsed % 60).padStart(2, '0')}
            </div>
          )}

          {/* Score submission — wins only */}
          {won && !submitted && (
            <div style={{ marginTop: 12, background: '#1a1a1b', border: '1px solid #2a2a2b', borderRadius: 10, padding: '14px 16px' }}>
              <div style={{ fontSize: 12, color: '#aaa', fontFamily: 'Arial, sans-serif', marginBottom: 8 }}>
                Add your name to the leaderboard:
              </div>
              <div style={{ display: 'flex', gap: 8 }}>
                <input
                  type="text"
                  value={nameInput}
                  onChange={e => setNameInput(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter') handleSubmitWordleScore(); }}
                  placeholder="Your name"
                  maxLength={20}
                  style={{
                    flex: 1, background: '#2a2a2b', border: '1px solid #3a3a3c',
                    borderRadius: 6, color: '#fff', padding: '8px 12px',
                    fontSize: 14, fontFamily: 'Arial, sans-serif', outline: 'none',
                  }}
                />
                <button onClick={handleSubmitWordleScore} style={{
                  background: '#ef4444', border: 'none', borderRadius: 6,
                  color: '#fff', fontWeight: 700, fontSize: 13,
                  padding: '8px 16px', cursor: 'pointer', fontFamily: 'Arial, sans-serif',
                  whiteSpace: 'nowrap',
                }}>Submit</button>
              </div>
              <button onClick={() => setSubmitted(true)} style={{
                marginTop: 8, background: 'transparent', border: 'none',
                color: '#555', fontSize: 12, cursor: 'pointer',
                fontFamily: 'Arial, sans-serif', padding: 0,
              }}>Skip</button>
            </div>
          )}
          {won && submitted && (
            <div style={{ textAlign: 'center', color: '#C8A951', fontSize: 13, fontFamily: 'Arial, sans-serif', marginTop: 10 }}>
              ✓ Score submitted!
            </div>
          )}

          <button onClick={onBack} style={{
            marginTop: 16, width: '100%', background: '#ef4444', border: 'none',
            color: '#fff', fontWeight: 700, fontSize: 15, borderRadius: 8,
            padding: '14px 0', cursor: 'pointer', fontFamily: 'Arial, sans-serif',
          }}>
            Back to Menu
          </button>
        </div>
      )}
    </div>
  );
}

// ─── MODE SELECTOR ───────────────────────────────────────────────────────────

function ModeCard({ bucketKey, onClick }) {
  const today = getTodayStr();
  const player = getDailyPlayer(bucketKey, today);
  const wordLen = player ? player.surname.length : 0;
  const tileSize = 28;
  const displayLen = Math.min(wordLen, 17);

  return (
    <button
      onClick={onClick}
      style={{
        background: '#1a1a1b', border: '2px solid #3a3a3c',
        borderRadius: 12, padding: '20px 24px',
        cursor: 'pointer', width: '100%', textAlign: 'left',
        color: '#fff', fontFamily: 'Arial, sans-serif',
        transition: 'border-color 0.2s, transform 0.15s',
      }}
      onMouseEnter={e => { e.currentTarget.style.borderColor = '#ef4444'; e.currentTarget.style.transform = 'translateY(-2px)'; }}
      onMouseLeave={e => { e.currentTarget.style.borderColor = '#3a3a3c'; e.currentTarget.style.transform = 'none'; }}
    >
      <div style={{ fontSize: 17, fontWeight: 800, marginBottom: 12 }}>{BUCKET_LABELS[bucketKey]}</div>
      <div style={{ display: 'flex', gap: 3, flexWrap: 'wrap' }}>
        {Array.from({ length: displayLen }).map((_, i) => (
          <div key={i} style={{
            width: tileSize, height: tileSize,
            border: '2px solid #3a3a3c', borderRadius: 2,
            background: 'transparent', flexShrink: 0,
          }} />
        ))}
        {wordLen > 17 && <div style={{ color: '#555', fontSize: 11, alignSelf: 'center', marginLeft: 4 }}>+{wordLen - 17}</div>}
      </div>
    </button>
  );
}

// ─── APP ROOT ────────────────────────────────────────────────────────────────

export default function App() {
  const [selectedBucket, setSelectedBucket] = useState(null);
  const [hintEnabled,    setHintEnabled]    = useState(true);

  return (
    <div style={{
      minHeight: '100vh', background: '#121213',
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      paddingBottom: 40,
    }}>
      {/* Top bar */}
      <div style={{
        width: '100%', borderBottom: '1px solid #3a3a3c',
        padding: '14px 20px', marginBottom: 24,
        background: '#121213',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        position: 'relative',
      }}>
        {/* Spacer left to balance logo */}
        <div style={{ width: 44 }} />
        {/* Title centre */}
        <div style={{ textAlign: 'center' }}>
          <div style={{
            fontFamily: "'Arial Black', Arial, sans-serif",
            fontWeight: 900, fontSize: 26, letterSpacing: 3,
            color: '#fff', textTransform: 'uppercase',
          }}>
            Gunners XI
          </div>
          <div style={{
            fontSize: 12, color: '#ef4444', letterSpacing: 2, marginTop: 2,
            fontFamily: 'Arial, sans-serif', fontWeight: 600, textTransform: 'uppercase',
          }}>
            Arsenal Wordle
          </div>
        </div>
        {/* TG Logo top-right */}
        <img src={TG_LOGO} alt="Touchline Gunners" style={{ width: 44, height: 44, objectFit: 'contain' }} />
      </div>

      {/* Watermark — shown on both menu and game screens */}
      <img src={TG_LOGO} alt="" aria-hidden="true" style={{
        position: 'fixed', top: '50%', left: '50%',
        transform: 'translate(-50%, -50%)',
        width: 260, height: 260, objectFit: 'contain',
        opacity: 0.06, pointerEvents: 'none', zIndex: 0,
        userSelect: 'none',
      }} />

      {selectedBucket === null ? (
        <div style={{ width: '100%', maxWidth: 420, padding: '0 16px' }}>
          <div style={{
            textAlign: 'center', marginBottom: 24,
            color: '#aaa', fontSize: 14,
            fontFamily: 'Arial, sans-serif', lineHeight: 1.6,
          }}>
            Guess today's Arsenal player.<br />
            Pick your word length to begin.
          </div>

          {/* Mode cards */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginBottom: 24 }}>
            {[4, 5, 6, '7plus'].map(k => (
              <ModeCard key={k} bucketKey={k} onClick={() => setSelectedBucket(k)} />
            ))}
          </div>

          {/* Hint toggle */}
          <div style={{
            background: '#1a1a1b', border: '1px solid #2a2a2b',
            borderRadius: 10, padding: '14px 18px',
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
            marginBottom: 16,
          }}>
            <div>
              <div style={{ color: '#fff', fontSize: 14, fontWeight: 700, fontFamily: 'Arial, sans-serif' }}>
                First name hint
              </div>
              <div style={{ color: '#666', fontSize: 12, fontFamily: 'Arial, sans-serif', marginTop: 2 }}>
                Reveals after 4 guesses
              </div>
            </div>
            <button
              onClick={() => setHintEnabled(h => !h)}
              style={{
                width: 52, height: 28, borderRadius: 14,
                background: hintEnabled ? '#ef4444' : '#3a3a3c',
                border: 'none', cursor: 'pointer',
                position: 'relative', transition: 'background 0.2s',
                flexShrink: 0,
              }}
            >
              <div style={{
                position: 'absolute', top: 3,
                left: hintEnabled ? 26 : 3,
                width: 22, height: 22, borderRadius: '50%',
                background: '#fff', transition: 'left 0.2s',
              }} />
            </button>
          </div>

          {/* Key legend */}
          <div style={{
            padding: 16, background: '#1a1a1b',
            borderRadius: 10, border: '1px solid #2a2a2b',
            color: '#888', fontSize: 12,
            fontFamily: 'Arial, sans-serif', lineHeight: 1.8,
          }}>
            🟩 Right letter, right place &nbsp;·&nbsp; 🟨 Right letter, wrong place &nbsp;·&nbsp; ⬛ Not in the name
          </div>
        </div>
      ) : (
        <WordleGame
          bucketKey={selectedBucket}
          hintEnabled={hintEnabled}
          onBack={() => setSelectedBucket(null)}
        />
      )}
    </div>
  );
}
